#include<cstdio>
#include<cstring>
#include<iostream>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;using namespace std;
const int N=2e6+10;vector<int> D[N],T[N];int ch[N][2],cnt=1,n,idx[N],loc[N];string q[N];

inline int Inv(const int &x){return x<=n?x+n:x-n;}
namespace TwoSat
{
	const int N=5e6+10,M=2e7+10;template<typename T> inline T min(const T &x,const T &y){return x<y?x:y;}
	int head[N],des[M],nxt[M],cgt,S=1,low[N],dfn[N],tot,stk[N],top,cdt,scc[N];bool iss[N];
	inline void ins(const int &x,const int &y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;}
	inline void tarjan(const int &u)
	{
		iss[stk[++top]=u]=true;low[u]=dfn[u]=++cdt; grep(u,i)
		{
			int v=des[i];if(!dfn[v])tarjan(v),low[u]=min(low[u],low[v]);
			else if(iss[v])low[u]=min(low[u],low[v]);
		}
		if(dfn[u]==low[u]){int v;++tot;do iss[v=stk[top--]]=false,scc[v]=tot;while(u!=v);}
	}
	inline bool Judge()
	{
		cdt=tot=0;memset(dfn,0,(S+2)<<2);memset(scc,0,(S+2)<<2);
		rep(1,S,i)if(!dfn[i])tarjan(i);
//		rep(1,S,i)printf("%d ",scc[i]);putchar('\n');
		rep(1,n,i)if(scc[i]==scc[i+n])return false; return true;
	}
}
using TwoSat::Judge;using TwoSat::ins;using TwoSat::S;using TwoSat::scc;
inline void ins(string &s,int idx)
{
	int p=1;for(unsigned i=0;i<s.length();++i){int &x=ch[p][s[i]=='1'];p=x?x:x=++cnt;}
	D[p].push_back(idx);// printf("ins %d :: %d\n",idx,p);
}
//idx[p] --> p子树内所有点没被选 
//idx[p]+1 --> p子树内存在点被选择 
inline void build(const int &u=1,const int &fa=0)
{
	if(!u)return;if(!D[u].size())build(ch[u][0],fa),build(ch[u][1],fa);
	else
	{
//		cout<<"build :: "<<u<<' '<<fa<<' '<<cur<<'\n';
		idx[u]=++S;++S;if(fa)ins(idx[fa],idx[u]),ins(idx[u]+1,idx[fa]+1);
		for(int v:D[u]){ins(idx[u],Inv(v));ins(v,idx[u]+1);}
		for(int v:D[fa]){ins(v,idx[u]);ins(idx[u]+1,Inv(v));}
		//S+i --> D[1]~D[i] 全部没被选
		//S+i+qn --> D[1]~D[i] 存在点被选
		//S+i+2*qn --> D[i]~D[qn] 全部没被选
		//S+i+3*qn --> D[i]~D[qn] 存在点被选 
		int qn=D[u].size();rep(1,qn,i)
		{
			int v=D[u][i-1];ins(S+i,Inv(v));ins(v,S+i+qn);ins(S+i+2*qn,Inv(v));ins(v,S+i+3*qn);
			if(i!=1)ins(S+i,S+i-1),ins(S+i-1+qn,S+i+qn),ins(v,S+i-1),ins(S+i-1+qn,Inv(v));
			if(i!=qn)ins(S+i+2*qn,S+i+1+2*qn),ins(S+i+1+3*qn,S+i+3*qn),ins(v,S+i+1+2*qn),ins(S+i+1+3*qn,Inv(v));
		}
		S+=4*qn;build(ch[u][0],u);build(ch[u][1],u);
	}
}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
	cin>>n;S=n*2;rep(1,n,i)
	{
		string &s=q[i];cin>>s;loc[i]=-1;
		for(unsigned j=0;j<s.length();++j)if(s[j]=='?'){loc[i]=j;s[j]='0';ins(s,i);s[j]='1';ins(s,i+n);break;}
		if(loc[i]==-1)ins(s,i),ins(s,i+n);
	}
	build();if(!Judge())return (cout<<"NO"<<'\n'),0;cout<<"YES"<<'\n';
	rep(1,n,i)
	{
		if(loc[i]==-1)cout<<q[i]<<'\n';
		else if(scc[i]<scc[i+n]){q[i][loc[i]]='0';cout<<q[i]<<'\n';}
		else{q[i][loc[i]]='1';cout<<q[i]<<'\n';}
	}
}
